    if horizon == 0:
        return DispatchPlan(charge_mw=[], discharge_mw=[], soc_mwh=[])
    spec = ctx.spec
    eff_c = float(spec.charge_efficiency)
    eff_d = float(spec.discharge_efficiency)
    p_max = float(spec.power_mw)
    c_max = float(spec.capacity_mwh)
    t_soc = float(spec.final_soc_target_mwh)
    soc = float(spec.initial_soc_mwh)
    charge_plan, discharge_plan, soc_trace = [], [], []
    low_a = float(np.quantile(prices, 0.35))
    high_a = float(np.quantile(prices, 0.75))
    for step in range(horizon):
        rem = horizon - step - 1
        p = prices[step]
        charge, discharge = 0.0, 0.0
        term_rem = t_soc - soc
        if rem > 0:
            if term_rem > rem * p_max * eff_c:
                charge = p_max
            elif term_rem < -rem * p_max / eff_d:
                discharge = p_max
            else:
                if p < low_a:
                    charge = p_max
                elif p > high_a:
                    discharge = p_max
        else:
            if term_rem > 0:
                charge = min(p_max, term_rem / eff_c)
            elif term_rem < 0:
                discharge = min(p_max, -term_rem * eff_d)
        charge = np.clip(charge, 0.0, (c_max - soc) / eff_c)
        discharge = np.clip(discharge, 0.0, soc * eff_d)
        if charge > 0 and discharge > 0:
            if charge > discharge * eff_d * eff_c:
                discharge = 0.0
            else:
                charge = 0.0
        soc += charge * eff_c - discharge / eff_d
        charge_plan.append(float(charge))
        discharge_plan.append(float(discharge))
        soc_trace.append(float(soc))
    return DispatchPlan(charge_mw=charge_plan, discharge_mw=discharge_plan, soc_mwh=soc_trace)

